<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { ElMessage } from 'element-plus'
import { Search, Van } from '@element-plus/icons-vue'
import { adminApi, type AdminOrder } from '@/api/services'

const statusLabels: Record<string, string> = { PENDING_PAYMENT: '待付款', PAID: '待发货', SHIPPED: '已发货', COMPLETED: '已完成', CANCELED: '已取消' }
const filters = reactive({ orderNo: '', userId: undefined as number | undefined, status: '' })
const orders = ref<AdminOrder[]>([]); const loading = ref(false); const page = ref(1); const pageSize = ref(20); const total = ref(0)
const detailVisible = ref(false); const detail = ref<AdminOrder>(); const shipVisible = ref(false); const shippingOrder = ref<AdminOrder>(); const shipping = ref(false)
const shipForm = reactive({ carrier: '', trackingNo: '' })
const money = (value: number) => Number(value || 0).toFixed(2)
const time = (value?: string) => value ? value.replace('T', ' ').slice(0, 19) : '-'
type TagType = 'success' | 'warning' | 'info' | 'primary' | 'danger'
const statusType = (status: string): TagType | undefined => ({ PAID: 'warning', SHIPPED: 'primary', COMPLETED: 'success', CANCELED: 'info' } as Record<string, TagType>)[status]
const load = async () => { loading.value = true; try { const result = await adminApi.orders({ orderNo: filters.orderNo || undefined, userId: filters.userId, status: filters.status || undefined, page: page.value, size: pageSize.value }); orders.value = result.items; total.value = result.total } finally { loading.value = false } }
const search = () => { page.value = 1; load() }
const showDetail = async (orderNo: string) => { detail.value = await adminApi.order(orderNo); detailVisible.value = true }
const openShip = (order: AdminOrder) => { shippingOrder.value = order; Object.assign(shipForm, { carrier: '', trackingNo: '' }); shipVisible.value = true }
const ship = async () => { if (!shippingOrder.value || !shipForm.carrier.trim() || !shipForm.trackingNo.trim()) return ElMessage.warning('请填写承运商和运单号'); shipping.value = true; try { await adminApi.ship(shippingOrder.value.orderNo, shipForm); ElMessage.success('订单已发货'); shipVisible.value = false; await load() } finally { shipping.value = false } }
onMounted(load)
</script>

<template><div><div class="admin-page-title"><div><span>交易履约</span><h1>订单管理</h1><p>按订单号、用户和状态查询，并完成已支付订单发货。</p></div></div><section class="admin-card"><div class="toolbar order-toolbar"><el-input v-model="filters.orderNo" placeholder="订单号" clearable :prefix-icon="Search" @keyup.enter="search" /><el-input-number v-model="filters.userId" :min="1" controls-position="right" placeholder="用户 ID" /><el-select v-model="filters.status" placeholder="全部状态" clearable><el-option v-for="(label, value) in statusLabels" :key="value" :label="label" :value="value" /></el-select><el-button type="primary" @click="search">查询</el-button></div><el-table v-loading="loading" :data="orders"><el-table-column prop="orderNo" label="订单号" min-width="210" /><el-table-column prop="userId" label="用户 ID" width="95" /><el-table-column label="金额" width="120"><template #default="scope">¥{{ money(scope.row.totalAmount) }}</template></el-table-column><el-table-column label="状态" width="110"><template #default="scope"><el-tag :type="statusType(scope.row.status)">{{ statusLabels[scope.row.status] || scope.row.status }}</el-tag></template></el-table-column><el-table-column label="创建时间" width="175"><template #default="scope">{{ time(scope.row.createdAt) }}</template></el-table-column><el-table-column label="操作" width="170" fixed="right"><template #default="scope"><el-button link type="primary" @click="showDetail(scope.row.orderNo)">详情</el-button><el-button v-if="scope.row.status === 'PAID'" link type="warning" :icon="Van" @click="openShip(scope.row)">发货</el-button></template></el-table-column></el-table><div class="admin-pagination"><el-pagination v-model:current-page="page" background layout="total, prev, pager, next" :page-size="pageSize" :total="total" @current-change="load" /></div></section><el-dialog v-model="detailVisible" title="订单详情" width="760px"><template v-if="detail"><el-descriptions :column="2" border><el-descriptions-item label="订单号">{{ detail.orderNo }}</el-descriptions-item><el-descriptions-item label="用户 ID">{{ detail.userId }}</el-descriptions-item><el-descriptions-item label="状态">{{ statusLabels[detail.status] || detail.status }}</el-descriptions-item><el-descriptions-item label="金额">¥{{ money(detail.totalAmount) }}</el-descriptions-item><el-descriptions-item label="收件人">{{ detail.receiverName }} {{ detail.receiverPhone }}</el-descriptions-item><el-descriptions-item label="物流">{{ detail.carrier || '-' }} {{ detail.trackingNo || '' }}</el-descriptions-item><el-descriptions-item label="地址" :span="2">{{ detail.receiverAddress }}</el-descriptions-item></el-descriptions><el-table :data="detail.items" class="detail-items"><el-table-column label="商品" min-width="280"><template #default="scope"><div class="table-product"><img :src="scope.row.mainImageUrl || 'https://placehold.co/80x80/eaf3ff/1677ff?text=DD'" /><div><b>{{ scope.row.productTitle }}</b><small>{{ scope.row.specJson }}</small></div></div></template></el-table-column><el-table-column label="单价" width="100"><template #default="scope">¥{{ money(scope.row.unitPrice) }}</template></el-table-column><el-table-column prop="quantity" label="数量" width="80" /><el-table-column label="小计" width="110"><template #default="scope">¥{{ money(scope.row.totalAmount) }}</template></el-table-column></el-table></template></el-dialog><el-dialog v-model="shipVisible" title="订单发货" width="480px"><el-form :model="shipForm" label-width="85px"><el-form-item label="订单号">{{ shippingOrder?.orderNo }}</el-form-item><el-form-item label="承运商" required><el-input v-model="shipForm.carrier" placeholder="例如：顺丰速运" /></el-form-item><el-form-item label="运单号" required><el-input v-model="shipForm.trackingNo" placeholder="请输入模拟运单号" /></el-form-item></el-form><template #footer><el-button @click="shipVisible = false">取消</el-button><el-button type="primary" :loading="shipping" @click="ship">确认发货</el-button></template></el-dialog></div></template>
